pio(int pp_fd, u_int8_t *c, bool in)	/* real code	*/
{
static int      errs;
u_int8_t        sval;
        ioctl(pp_fd, in ? PPIGDATA : PPISDATA, c);      
        if (errno && errno != EINTR)    {
                prgmerr(0, "ioc = %d", *c);
                if (errs++ > 2)	clean_up(-errs);
        }               
}                

